<?php
namespace App\Http\Resources; use Illuminate\Http\Request; use Illuminate\Http\Resources\Json\JsonResource;
class ActivationResource extends JsonResource { public function toArray(Request $request): array { $r=$this->resource; return ['token'=>$r['token'],'tokenType'=>'Bearer','expiresIn'=>config('jwt.ttl')*60,'tenantUuid'=>$r['restaurant']->tenant->uuid,'restaurantUuid'=>$r['restaurant']->uuid,'deviceUuid'=>$r['device']->uuid,'activatedAt'=>$r['device']->activated_at->toISOString(),'configuration'=>['restaurantName'=>$r['restaurant']->name,'outletName'=>'Main Outlet','terminalName'=>$r['device']->computer_name ?: 'POS Terminal','timezone'=>$r['restaurant']->timezone,'currency'=>$r['restaurant']->currency,'locale'=>$r['restaurant']->locale,'features'=>$r['license']->plan->features]]; } }
